mapper.select:
SELECT COUNT(*) > 0
FROM bookings
WHERE shop_id = #{shopId} 
  AND appointment_datetime = #{appointmentDateTime}
  AND deleted_at IS NULL
  AND status NOT IN ('CANCELLED', 'NO_SHOW')
  AND id != #{excludeId}

mapper.update:
UPDATE bookings
SET deleted_at = CURRENT_TIMESTAMP, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
